from flask import Flask, request, redirect, make_response
import uuid
import time

app = Flask(__name__)

SESSIONS = {}
SESSION_COOKIE_NAME = "session_id"
SESSION_LIFETIME_SECONDS = 60 * 60 * 24 * 7


def create_session(username):
    session_id = str(uuid.uuid4())
    SESSIONS[session_id] = {
        "username": username,
        "created_at": int(time.time()),
        "expires_at": int(time.time()) + SESSION_LIFETIME_SECONDS,
    }
    return session_id


def get_session(session_id):
    if not session_id:
        return None
    session_data = SESSIONS.get(session_id)
    if not session_data:
        return None
    if session_data["expires_at"] < int(time.time()):
        del SESSIONS[session_id]
        return None
    session_data["expires_at"] = int(time.time()) + SESSION_LIFETIME_SECONDS
    return session_data


def destroy_session(session_id):
    if session_id in SESSIONS:
        del SESSIONS[session_id]


def current_user():
    session_id = request.cookies.get(SESSION_COOKIE_NAME)
    session_data = get_session(session_id)
    if session_data:
        return session_data["username"]
    return None


@app.route("/")
def index():
    username = current_user()
    if username:
        return "Hello, %s! You are logged in. Visit /logout to sign out." % username
    return 'You are not logged in. Visit /login?username=yourname to sign in.'


@app.route("/login")
def login():
    username = request.args.get("username")
    if not username:
        return 'Provide a username: /login?username=yourname', 400

    session_id = create_session(username)
    response = make_response(redirect("/"))
    response.set_cookie(
        SESSION_COOKIE_NAME,
        session_id,
        max_age=SESSION_LIFETIME_SECONDS,
        httponly=True,
    )
    return response


@app.route("/logout")
def logout():
    session_id = request.cookies.get(SESSION_COOKIE_NAME)
    if session_id:
        destroy_session(session_id)

    response = make_response(redirect("/"))
    response.set_cookie(SESSION_COOKIE_NAME, "", expires=0)
    return response


@app.route("/profile")
def profile():
    username = current_user()
    if not username:
        return redirect("/")
    return "Profile page for %s" % username


if __name__ == "__main__":
    app.run(debug=True)